// DecodeListReplayResultsRequest returns a decoder for requests sent to the
// nlpolicies listReplayResults endpoint.
func DecodeListReplayResultsRequest(mux goahttp.Muxer, decoder func(*http.Request) goahttp.Decoder) func(*http.Request) (*nlpolicies.ListReplayResultsPayload, error) {
	return func(r *http.Request) (*nlpolicies.ListReplayResultsPayload, error) {
		var payload *nlpolicies.ListReplayResultsPayload
		var (
			runID            string
			decision         *string
			cursor           *string
			pageLimit        *int
			apikeyToken      *string
			sessionToken     *string
			projectSlugInput *string
			err              error
		)
		qp := r.URL.Query()
		runID = qp.Get("run_id")
		if runID == "" {
			err = goa.MergeErrors(err, goa.MissingFieldError("run_id", "query string"))
		}
		err = goa.MergeErrors(err, goa.ValidateFormat("run_id", runID, goa.FormatUUID))
		decisionRaw := qp.Get("decision")
		if decisionRaw != "" {
			decision = &decisionRaw
		}
		cursorRaw := qp.Get("cursor")
		if cursorRaw != "" {
			cursor = &cursorRaw
		}
		{
			pageLimitRaw := qp.Get("page_limit")
			if pageLimitRaw != "" {
				v, err2 := strconv.ParseInt(pageLimitRaw, 10, strconv.IntSize)
				if err2 != nil {
					err = goa.MergeErrors(err, goa.InvalidFieldTypeError("page_limit", pageLimitRaw, "integer"))
				}
				pv := int(v)
				pageLimit = &pv
			}
		}
		if pageLimit != nil {
			if *pageLimit < 1 {
				err = goa.MergeErrors(err, goa.InvalidRangeError("page_limit", *pageLimit, 1, true))
			}
		}
		if pageLimit != nil {
			if *pageLimit > 200 {
				err = goa.MergeErrors(err, goa.InvalidRangeError("page_limit", *pageLimit, 200, false))
			}
		}
		apikeyTokenRaw := r.Header.Get("Gram-Key")
		if apikeyTokenRaw != "" {
			apikeyToken = &apikeyTokenRaw
		}
		sessionTokenRaw := r.Header.Get("Gram-Session")
		if sessionTokenRaw != "" {
			sessionToken = &sessionTokenRaw
		}
		projectSlugInputRaw := r.Header.Get("Gram-Project")
		if projectSlugInputRaw != "" {
			projectSlugInput = &projectSlugInputRaw
		}
		if err != nil {
			return payload, err
		}
		payload = NewListReplayResultsPayload(runID, decision, cursor, pageLimit, apikeyToken, sessionToken, projectSlugInput)
		if payload.ApikeyToken != nil {
			if strings.Contains(*payload.ApikeyToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.ApikeyToken, " ", 2)[1]
				payload.ApikeyToken = &cred
			}
		}
		if payload.ProjectSlugInput != nil {
			if strings.Contains(*payload.ProjectSlugInput, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.ProjectSlugInput, " ", 2)[1]
				payload.ProjectSlugInput = &cred
			}
		}
		if payload.SessionToken != nil {
			if strings.Contains(*payload.SessionToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.SessionToken, " ", 2)[1]
				payload.SessionToken = &cred
			}
		}

		return payload, nil
	}
}

